def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = np.inf
            continue
        temp_score = 0
        for k in range(1, 21):
            term = ((-1) ** k) * (ratio ** k) / (k ** 1.5)
            temp_score += term
            if temp_score < -5:
                temp_score = -5
                break
        if ratio < 0.3:
            priorities[i] = temp_score * np.sqrt(capacity + 1)
        elif 0.3 <= ratio < 0.7:
            mod_factor = 0
            for m in range(1, 6):
                mod_factor += np.sin(m * ratio * np.pi) / m
            priorities[i] = temp_score * np.exp(-mod_factor)
        else:
            penalty = 0
            for n in range(1, 5):
                if n % 2 == 0:
                    penalty += np.log(capacity + n)
                else:
                    penalty -= np.sqrt(abs(item - n))
            if penalty < 1:
                penalty = 1
            priorities[i] = temp_score / penalty
        if capacity % 2 == 0:
            priorities[i] += np.tanh(item / (capacity + 1))
        else:
            priorities[i] -= np.arctan(capacity / (item + 1))
        if priorities[i] > 10:
            priorities[i] = 10
        elif priorities[i] < -10:
            priorities[i] = -10
    return priorities
